// Delay fonksiyonu
void delay(unsigned int a) {
    unsigned int i, j;
    for(i = 0; i < a; i++) {
        for(j = 0; j < 127; j++);
    }
}

// Karakter lookup index bulucu
int getCharIndex(char c) {
    if (c >= '1' && c <= '9') return c - 49;
    if (c >= 'A' && c <= 'Z') return c - 56;
    if (c >= 'a' && c <= 'z') return c - 62;
    if (c == '0') return 60; // Örnek olarak '0' sona eklenmiş varsayılıyor
    return 61; // boşluk veya tanımsız karakter için boşluk karakteri indexi
}

